solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    char nom[20];
    int note;
} Etudiant;

int cmp_note_desc(const void *a, const void *b) {
    const Etudiant *ea = (const Etudiant *)a;
    const Etudiant *eb = (const Etudiant *)b;
    return (eb->note > ea->note) - (eb->note < ea->note);
}

int main(void) {
    Etudiant classe[] = {
        {"Alice", 15},
        {"Bob", 18},
        {"Charlie", 12},
        {"Diana", 17}
    };
    int n = sizeof(classe) / sizeof(classe[0]);

    qsort(classe, n, sizeof(Etudiant), cmp_note_desc);

    for (int i = 0; i < n; i++) {
        printf("%d. %s : %d\n", i + 1, classe[i].nom, classe[i].note);
    }
    return 0;
}

validation.test_code:
void test_qsort_descending(void) {
    Etudiant classe[] = {
        {"Alice", 15},
        {"Bob", 18},
        {"Charlie", 12},
        {"Diana", 17}
    };
    int n = sizeof(classe) / sizeof(classe[0]);
    qsort(classe, n, sizeof(Etudiant), cmp_note_desc);
    TEST_ASSERT_EQUAL_INT(18, classe[0].note);
    TEST_ASSERT_EQUAL_INT(17, classe[1].note);
    TEST_ASSERT_EQUAL_INT(15, classe[2].note);
    TEST_ASSERT_EQUAL_INT(12, classe[3].note);
}

void test_comparator_basic(void) {
    Etudiant ea = {"Alice", 15};
    Etudiant eb = {"Bob", 18};
    int result = cmp_note_desc(&ea, &eb);
    TEST_ASSERT_TRUE(result > 0);
}

void test_comparator_equal(void) {
    Etudiant ea = {"Alice", 15};
    Etudiant eb = {"Bob", 15};
    int result = cmp_note_desc(&ea, &eb);
    TEST_ASSERT_EQUAL_INT(0, result);
}

void test_array_size_computation(void) {
    Etudiant classe[] = {
        {"A", 10},
        {"B", 20},
        {"C", 30}
    };
    int n = sizeof(classe) / sizeof(classe[0]);
    TEST_ASSERT_EQUAL_INT(3, n);
}

int main(void) {
    RUN_TEST(test_qsort_descending);
    RUN_TEST(test_comparator_basic);
    RUN_TEST(test_comparator_equal);
    RUN_TEST(test_array_size_computation);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

